@@ -157,6 +170,14 @@ export class RpcSession {
   constructor(cpp, transport, registry, options = {}) {
     this.#cpp = cpp;
     this.#exp = cpp._exports;        // shorthand the hot paths use
+    // Cache wasm-side constants once. Each cpp_*_ptr/_capacity export is
